  ('heelevel3-7be5e2bb-moex-00114', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '多數當事人關於訴訟標的之權利義務關係，在事實上或法律上有同一或同類原因時，有關訴訟程 序之敘述，下列何者錯誤？', '["可以成立共同訴訟，一同擔任原告或被告", "如果當事人分別起訴，法院得命其合併辯論及合併裁判", "共同訴訟之訴訟標的有合一確定必要時，共同訴訟人中一人不利於全體之行為，效力不及於全 體共同訴訟人", "共同訴訟之訴訟標的無論有無合一確定必要，當事人合意停止訴訟後，續行訴訟必須經全體同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00115', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '依行政訴訟法規定之都市計畫審查程序，行政法院審查認定都市計畫違法時，下列何者非判決主 文得宣告之內容？', '["都市計畫違法者，宣告無效或違法", "都市計畫發布後始發生違法原因者，應宣告自違法原因發生時起失效", "同一都市計畫中未經原告請求，而與原告請求宣告無效之部分具不可分關係，經法院審查認定 違法者，併宣告撤銷", "依法僅得為違法之宣告者，應宣告其違法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00116', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '某市政府自行興建設置之公立醫院委託私立醫學院經營，因原先所設置之手扶梯未定期保養而故 障，導致病患摔傷。下列敘述何者正確？', '["公共設施委託私人管理，因管理欠缺致人民身體受損害者，負國家賠償責任", "私立醫學院與病患間雖係私法關係，仍不得依民法向醫院求償", "委託屬公法關係，故病患不得依民法向醫院求償", "如病患為外國人者，則無法依國家賠償法求償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
